python3 -c "
import sys, json, re
from pathlib import Path
try:
    raw = sys.stdin.read()
    data = json.loads(raw)
    cmd = data.get('tool_input', {}).get('command', '')
    if 'git commit' not in cmd:
        sys.exit(0)
    env_path = Path('.env')
    if not env_path.exists():
        sys.exit(0)
    desc = ''
    for line in env_path.read_text().splitlines():
        if line.startswith('AGENT_DESCRIPTION='):
            desc = line.split('=', 1)[1].strip().strip('\"').strip(\"'\")
            break
    if desc:
        sys.exit(0)
    has_tools = Path('src/tools').exists() and any(p for p in Path('src/tools').glob('*.py') if p.name != '__init__.py')
    has_skills = Path('src/skills').exists() and any(Path('src/skills').glob('*.md'))
    if has_tools or has_skills:
        print('CARD-DESCRIPTION-HOOK: AGENT_DESCRIPTION in .env is blank. A2A registries use this field for agent discovery — without it the agent is invisible to semantic matching. Run /update-card-description to generate one from current tools and skills before committing.')
except Exception:
    pass
" 2>/dev/null || true

